                    </el-col>
                </el-row>
            </div>
        </div>
        <div class="card bottom-box">
            <div class="line-echarts">
                <hoursLine ref="hoursLineRef" />
            </div>
        </div>
    </div>
</template>

<script setup lang="ts" name="dataVisualize">
import { onMounted, ref } from "vue";
import { getDashboardData } from "@/api/modules/dashboard";
import pie from "./components/pie.vue";
import hoursLine from "./components/hoursLine.vue";
import { DashBoard } from "@/api/interface";
onMounted(async () => {
    await loadData();
});
const reportData = ref<DashBoard.PeriodData[]>([]);
const pieRef = ref<InstanceType<typeof pie> | null>(null);
const hoursLineRef = ref<InstanceType<typeof hoursLine> | null>(null);
const loadData = async (tabIndex = 0) => {
    const result = await getDashboardData();
    reportData.value = [result.data.today, result.data.yesterday];
    const pieData = reportData.value[tabIndex];
    const rate = (pieData.status3Count! + pieData.status5Count!) /
        (
            pieData.status0Count! +
            pieData.status1Count! +
            pieData.status2Count! +
            pieData.status3Count! +
            pieData.status4Count! +
            pieData.status5Count! +
            pieData.status6Count! +
            pieData.status7Count!) * 100;
    pieRef.value!.acceptParams([
        { value: pieData.status0Count || 0, name: "未支付" },
        { value: pieData.status1Count || 0, name: "支付中" },
        { value: pieData.status2Count || 0, name: "支付成功" },
        { value: pieData.status3Count || 0, name: "回调成功" },
        { value: pieData.status4Count || 0, name: "回调失败" },
        { value: pieData.status5Count || 0, name: "已结算" },
        { value: pieData.status6Count || 0, name: "失效" },
        { value: pieData.status7Count || 0, name: "卡密错误" }
    ], isNaN(rate) ? "暂无" : rate.toFixed(2) + "%");
    hoursLineRef.value!.acceptParams(pieData.hours24);
};
const tabActive = ref(0);

const tabData = [
    { label: "今日", value: 0 },
    { label: "昨日", value: 1 },
];
const onTabChange = (tab, event) => {
    loadData(tabData[tab.index].value);
}
</script>

<style scoped lang="scss">
@import "./index.scss";
</style>
